const src = $input.first().json;
const params = src.query || src;
const mode = params['hub.mode'] || params['hub_mode'] || '';
const verifyToken = params['hub.verify_token'] || params['hub_verify_token'] || '';
const challenge = params['hub.challenge'] || params['hub_challenge'] || '';

if (mode === 'subscribe' && verifyToken === process.env.WHATSAPP_VERIFY_TOKEN) {
  return [{ json: { challenge, valid: true } }];
}
return [{ json: { valid: false } }];

const src = $input.first().json;
const body = src.body || src;

let entry, change, value;
try {
  entry = (body.entry || [])[0];
  change = (entry.changes || [])[0];
  value = change.value || {};
} catch(e) {
  return [{ json: { ok: false, reason: 'invalid_payload' } }];
}

const messages = value.messages || [];
if (!messages.length) {
  return [{ json: { ok: false, reason: 'no_message' } }];
}

const msg = messages[0];
const contacts = value.contacts || [];
const contact = contacts[0] || {};
const contactName = (contact.profile && contact.profile.name) || '';
const from = msg.from || '';
const phone = '+' + from;
const type = msg.type || 'text';
const text = (msg.text && msg.text.body) || (msg.interactive && (msg.interactive.button_reply && msg.interactive.button_reply.title || msg.interactive.list_reply && msg.interactive.list_reply.title)) || '';
const timestamp = msg.timestamp || '';

return [{ json: { ok: true, phone, name: contactName, messageType: type, text, timestamp } }];

const parsed = $('Parse inbound').first().json;
if (!parsed.ok) {
  return [{ json: { intent: 'unknown', phone: '', name: '', text: '' } }];
}
const text = (parsed.text || '').toLowerCase();
const phone = parsed.phone;
const name = parsed.name;

let intent = 'unknown';
if (/precio|costo|cu[aá]nto/.test(text)) {
  intent = 'precio';
} else if (/tiempo|demora|cu[aá]nto se demora/.test(text)) {
  intent = 'tiempo';
} else if (/garant[ií]a/.test(text)) {
  intent = 'garantia';
} else if (/financiaci[oó]n|cr[eé]dito/.test(text)) {
  intent = 'financiacion';
} else if (/hablar|asesor|humano|agente/.test(text)) {
  intent = 'escalate';
} else if (/s[ií]|cotizar|cotizaci[oó]n/.test(text)) {
  intent = 'start_quote';
} else if (/stop|baja|cancelar/.test(text)) {
  intent = 'optout';
}

return [{ json: { intent, phone, name, text } }];

const d = $input.first().json;
const name = d.name || 'Cliente';
const phone = d.phone;
const intent = d.intent;

const responses = {
  precio: `Hola ${name}! Los sistemas solares en Colombia van de $8M a $80M COP según capacidad (3-30 kWp). Te envío una cotización personalizada: solar-hub.co`,
  tiempo: `Una instalación residencial toma 1-3 días. El trámite AGPE ante el OR toma ~30 días hábiles adicionales.`,
  garantia: `Paneles: 25 años de rendimiento. Inversores: 5-10 años. Instalación RETIE: 1 año por defecto de diseño.`,
  financiacion: `Ofrecemos opciones de leasing solar y crédito verde Bancóldex. Escríbenos a info@alebas.co para más info.`,
  escalate: `Entendido ${name}, te conecto con un asesor. En horario L-V 8am-6pm te responden en minutos.`,
  start_quote: `Perfecto ${name}! Empieza tu cotización solar aquí: solar-hub.co — Te toma 3 minutos.`,
  optout: `Listo ${name}, no te enviaremos más mensajes. Si cambias de opinión, escríbenos.`
};

const responseText = responses[intent] || `Hola ${name}! Escríbenos a info@alebas.co o visita solar-hub.co para más información.`;

const phoneNumberId = process.env.WHATSAPP_PHONE_NUMBER_ID;
const token = process.env.WHATSAPP_ACCESS_TOKEN;
const url = 'https://graph.facebook.com/v18.0/' + phoneNumberId + '/messages';
const body = JSON.stringify({
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: phone,
  type: 'text',
  text: { body: responseText }
});

return [{ json: { phone, responseText, url, token, body } }];
